class PairProcessor:
    def __init__(self):
        self.counter = 0

    def process_pair(self, k, v):
        self.counter += 1
        return (k, v * 2)

    def process(self, pairs):
        out = []
        for item in pairs:
            # BUG: item is tuple but some entries have only 1 value
            for k, v in item:
                out.append(self.process_pair(k, v))
        return out


def process(pairs):
    return PairProcessor().process(pairs)


def main():
    pairs = [[('a', 1), ('b', 2)], [('c',)]]
    out = process(pairs)
    print(out)


if __name__ == '__main__':
    main()
